#include <pthread.h>
#include <stdio.h>
#include <stdlib.h>

int sum; /* bu veri thread'ler tarafindan paylasiliyor */
void *runner(void *param); /* thread'ler bu fonksiyonu cagirir */

int main(int argc, char *argv[])
{
    pthread_t tid;           /* thread tanimlayicisi */
    pthread_attr_t attr;     /* thread ozellikleri */

    /* thread'in varsayilan ozelliklerini ayarla */
    pthread_attr_init(&attr);
    /* thread'i olustur */
    pthread_create(&tid, &attr, runner, argv[1]);
    /* thread'in bitmesini bekle */
    pthread_join(tid, NULL);

    printf("sum = %d\n", sum);
}

/* Thread bu fonksiyonda calisacak */
void *runner(void *param)
{
    int i, upper = atoi(param);
    sum = 0;

    for (i = 1; i <= upper; i++)
        sum += i;

    pthread_exit(0);
}

#define NUM_THREADS 10

/* birlestirilecek thread dizisi */
pthread_t workers[NUM_THREADS];

for (int i = 0; i < NUM_THREADS; i++)
    pthread_join(workers[i], NULL);

// Runnable arayuzunu uygulama
class Task implements Runnable {
    public void run() {
        System.out.println("I am a thread.");
    }
}

// Thread olusturma ve baslatma
Thread worker = new Thread(new Task());
worker.start();

// Thread'in bitmesini bekleme
try {
    worker.join();
} catch (InterruptedException ie) { }

